Data Processing
We begin by constructing a data processing pipeline that includes data retrieval, parsing, and cleaning.

url &lt;- "https://api.census.gov/data/2022/acs/acs1/pums?get=SEX,AGEP,PWGTP,SCHL&key=1c79cd9423b45d9bcae0f21f1c8080b2d8560a24"

# ---- GET Function ----
get_census_data &lt;- function(url){
  res &lt;- httr::GET(url)
  if(httr::status_code(res) != 200){
    stop("API request failed")
  }

  return(res)
}

# ---- Parse Function ----
parse_to_tibble &lt;- function(res) {
  txt &lt;- content(res, as = "text", encoding = "UTF-8")
  json &lt;- fromJSON(txt)

  df &lt;- as.data.frame(json)
  colnames(df) &lt;- df[1,]
  df &lt;- df[-1,]

  as_tibble(df)
}

process_geo_subset &lt;- function(geo = "state", geo_filter = "37") {
  if(geo_filter == "all") geo_filter &lt;- "37"
  paste0("for=", geo, ":", geo_filter)
}
